const uploadUrl = $('upload_image_to_linkedin').first().json.value.uploadMechanism['com.linkedin.digitalmedia.uploading.MediaUploadHttpRequest'].uploadUrl;                                                         

  return [{                                                                                                                                                                                                           
    json: { uploadUrl },                                                                                                                                                                                              
    binary: $('PollinationImageGenerate').first().binary    
  }];

const linkedinPost = $('Bundle Outputs').first().json.linkedin_post;
  const assetUrn = $('upload_image_to_linkedin').first().json.value.asset;

  return [{
    json: {                                                                                                                                                       
      author: "urn:li:person:SY7-OYurt9",
      lifecycleState: "PUBLISHED",
      specificContent: {
        "com.linkedin.ugc.ShareContent": {
          shareCommentary: { text: linkedinPost },                                                                                                                
          shareMediaCategory: "IMAGE",
          media: [{ status: "READY", media: assetUrn }]                                                                                                           
        }                                                                                                                                                         
      },
      visibility: {                                                                                                                                               
        "com.linkedin.ugc.MemberNetworkVisibility": "PUBLIC"
      }
    }
  }];

const resumeUrl = $execution.resumeUrl;                                                                                                                         
  const x_post = $('ParseClaudeResponse').first().json.x_post;
  const linkedin_post = $('ParseClaudeResponse').first().json.linkedin_post;                                                                                      
  const hashtags = $('ParseClaudeResponse').first().json.hashtags;

  const approveUrl = `${resumeUrl}&action=approve`;                                                                                                               
  const rejectUrl = `${resumeUrl}&action=reject`;

  return [{       
    json: {
      unfurl_links: false,                                   
      unfurl_media: false,
      channel: "#all-n8n-post-approver",
      blocks: [                                                                                                                                                   
        {
          type: "section",                                                                                                                                        
          text: { type: "mrkdwn", text: "📝 *New Social Post Ready for Review*" }
        },                                                                                                                                                        
        {
          type: "section",                                                                                                                                        
          text: { type: "mrkdwn", text: `*X Post:*\n${x_post}` }
        },
        {
          type: "section",
          text: { type: "mrkdwn", text: `*LinkedIn Post:*\n${linkedin_post}` }                                                                                    
        },
        {                                                                                                                                                         
          type: "section",
          text: {
            type: "mrkdwn",                                                                                                                                       
            text: `*Hashtags:* ${Array.isArray(hashtags) ? hashtags.join(', ') : hashtags}`
          }                                                                                                                                                       
        },        
        {
          type: "section",
          text: {                                                                                                                                                 
            type: "mrkdwn",
            text: `<${approveUrl}|✅ Approve & Post>   <${rejectUrl}|❌ Reject>`                                                                                  
          }                                                                                                                                                       
        }
      ]                                                                                                                                                           
    }             
  }];
